// ============================================================
// NÓ 2 — Extrair e Tratar Dados do Webhook
// ============================================================
// Entrada: payload bruto do webhook do Monday.com
// Saída: objeto limpo com todos os dados necessários para o fluxo
// ============================================================

const event = $input.first().json.body.event;
const cols = event.columnValues;

// --- Extração dos campos ---
const nomeEmpregado = cols.dropdown_mktadatt.chosenValues[0].name.trim();
const dataInicio = cols.date_mktayxhb.date;       // "2026-03-16"
const dataFim = cols.date_mktasnwq.date;           // "2026-03-20"
const optanteVT = (cols.optante___vt?.label?.text || "NÃO").toUpperCase() === "SIM";
const trabalhaSabado = (cols.color_mktaavmp?.label?.text || "NÃO").toUpperCase() === "SIM";
const interior = (cols.color__1?.label?.text || "NÃO").toUpperCase() === "SIM";
const contratoOrgao = (cols.color_mktcnxwn?.label?.text || "").toUpperCase().trim();

// IDs do Monday para atualizações futuras
const boardId = event.boardId;
const itemId = event.pulseId;

// --- Tratamento do nome para a URL do RM ---
// A API do RM espera o nome com % para o LIKE, ex: %JAMILE JORGINA DOS SANTOS%
// E precisa de encoding na URL
const nomeParaRM = encodeURIComponent(`%${nomeEmpregado}%`);

// URL completa montada para o HTTP Request do próximo nó que precisar
const urlRM = `https://003080:.2099840340@contatoservicos165112.rm.cloudtotvs.com.br:8051/api/framework/v1/consultaSQLServer/RealizaConsulta/BEN%202/3/P/?parameters=$CODCOLIGADA%3D3%3BNOME%3D${nomeParaRM}`;

return [{
  json: {
    // Dados do empregado
    nomeEmpregado,
    nomeParaRM,
    urlRM,

    // Configurações de benefício
    optanteVT,
    trabalhaSabado,
    interior,
    contratoOrgao,

    // Período
    dataInicio,
    dataFim,

    // IDs Monday (para atualizações futuras)
    boardId,
    itemId
  }
}];

// ============================================================
// NÓ 3 — Calcular Dias Úteis (VR e VT com regras distintas)
// ============================================================
// Entrada: dados tratados do Nó 2
// Saída: mesmos dados + diasVR e diasVT calculados
// ============================================================
// Regra:
//   - diasVR = dias úteis seg-sex (sábado NUNCA conta para VR)
//   - diasVT = dias úteis seg-sex, MAS se trabalhaSabado = true,
//     sábados no período também contam para VT
//   - Se optanteVT = false, diasVT = 0
//   - Domingos nunca contam
// ============================================================

const dados = $input.first().json;

const inicio = new Date(dados.dataInicio + "T00:00:00");
const fim = new Date(dados.dataFim + "T00:00:00");

let diasVR = 0;
let diasVT = 0;

// Percorre cada dia do período (inclusive início e fim)
const atual = new Date(inicio);
while (atual <= fim) {
  const diaSemana = atual.getDay(); // 0=Dom, 1=Seg, ..., 5=Sex, 6=Sáb

  if (diaSemana >= 1 && diaSemana <= 5) {
    // Seg a Sex: conta para VR e VT
    diasVR++;
    diasVT++;
  } else if (diaSemana === 6 && dados.trabalhaSabado) {
    // Sábado: conta APENAS para VT se trabalha sábado
    diasVT++;
  }
  // Domingo: não conta para nada

  atual.setDate(atual.getDate() + 1);
}

// Se não é optante de VT, zera os dias de VT
if (!dados.optanteVT) {
  diasVT = 0;
}

return [{
  json: {
    ...dados,
    diasVR,
    diasVT
  }
}];

// ============================================================
// NÓ 6 — Identificar Regra de Benefício
// ============================================================
// Entrada: 
//   - Contrato/Órgão do Webhook (color_mktcnxwn)
//   - Função do RM (HTTP Request)
//   - Dados do Nó 2 e 3 via referência direta
// Saída: valores unitários de VR e VT por dia + dados consolidados
// ============================================================

// --- Referências diretas aos nós (não depende do $input) ---
const dadosNó3 = $('Code in JavaScript1').first().json;
const contrato = $('Webhook').first().json.body.event.columnValues.color_mktcnxwn.label.text.toUpperCase().trim();
const funcaoRM = $('HTTP Request').first().json['Função'].toUpperCase().trim();
const optanteVT = dadosNó3.optanteVT;

// Dados do RM para manter no fluxo (histórico futuro)
const dadosRM = {
  nomeRM: $('HTTP Request').first().json['Nome do Intermitente'],
  secaoRM: $('HTTP Request').first().json['Seção'],
  descricaoSecaoRM: $('HTTP Request').first().json['Descrição Seção'],
  chapaRM: $('HTTP Request').first().json['Matrícula/Chapa'],
  dataAdmissaoRM: $('HTTP Request').first().json['Data de Admissão'],
  funcaoRM: $('HTTP Request').first().json['Função'],
};

// --- Lógica de identificação ---
let vrDia = 0;
let vtDia = 0;
let regraAplicada = '';

if (contrato === 'DETRAN') {

  if (funcaoRM.includes('PORTARIA')) {
    vrDia = 514.50 / 30;
    regraAplicada = 'DETRAN - Agente de Portaria';
  } else if (funcaoRM.includes('MOTO BOY')) {
    vrDia = 27.00;
    regraAplicada = 'DETRAN - Moto Boy';
  } else {
    vrDia = 588.00 / 30;
    regraAplicada = `DETRAN - Outras Funções (${dadosRM.funcaoRM})`;
  }
  vtDia = 10.00;

} else if (contrato === 'TRE PB') {

  vrDia = 660.00 / 30;
  vtDia = 10.40;
  regraAplicada = 'TRE PB';

} else {

  // SEDUC SEDE, SEDUC ESCOLA, SEDUC INTERIOR, CETAM, SEMSA, URUGUAIANA, ADMINISTRATIVO
  vrDia = 24.50;
  vtDia = 10.00;
  regraAplicada = `Padrão (${contrato})`;

}

// Se não é optante de VT, zera o valor unitário de VT
if (!optanteVT) {
  vtDia = 0;
}

// Arredonda valores unitários para 2 casas decimais
vrDia = Math.round(vrDia * 100) / 100;
vtDia = Math.round(vtDia * 100) / 100;

return [{
  json: {
    // Dados do Nó 2/3 (preservados)
    ...dadosNó3,
    // Dados do RM
    ...dadosRM,
    // Dados calculados neste nó
    contrato,
    funcao: dadosRM.funcaoRM,
    regraAplicada,
    vrDia,
    vtDia
  }
}];

// ============================================================
// NÓ 7 — Calcular Valor Bruto Total
// ============================================================
// Entrada: dados do Nó 6 com vrDia, vtDia, diasVR, diasVT
// Saída: mesmos dados + valorBrutoVR e valorBrutoVT
// ============================================================

const dados = $input.first().json;

const valorBrutoVR = Math.round(dados.vrDia * dados.diasVR * 100) / 100;
const valorBrutoVT = Math.round(dados.vtDia * dados.diasVT * 100) / 100;

return [{
  json: {
    ...dados,
    valorBrutoVR,
    valorBrutoVT
  }
}];

// ============================================================
// NÓ 8 — Buscar TODAS as dívidas PENDENTE/PARCIAL do empregado
// ============================================================
// limit: 100. Filtragem por status feita no Nó 9.
// ============================================================

const dados = $input.first().json;
const nomeEmpregado = dados.nomeEmpregado;

const query = `query {
  items_page_by_column_values(
    limit: 100
    board_id: 18400981023
    columns: [
      { column_id: "dropdown_mm0rgfrx", column_values: ["${nomeEmpregado}"] }
    ]
  ) {
    items {
      id
      name
      column_values {
        id
        text
        value
      }
    }
  }
}`;

return [{
  json: {
    ...dados,
    mondayDescontoQuery: { query }
  }
}];

// ============================================================
// NÓ 9 — Parsear retorno do Monday: array de dívidas FIFO
// ============================================================

const dados = $('Code in JavaScript3').first().json;

const COL_STATUS         = 'color_mm0r8mjr';
const COL_DATA_INICIO    = 'date_mm0r6tyr';
const COL_DATA_FIM       = 'date_mm0rzpyv';
const COL_DESCONTO_VR    = 'numeric_mm0rgsaw';
const COL_DESCONTO_VT    = 'numeric_mm0r5tca';
const COL_RESIDUAL_VR    = 'numeric_mm0r1691';
const COL_RESIDUAL_VT    = 'numeric_mm0rtwwg';
const COL_DESCONTADO_VR  = 'numeric_mm0rqy6z';
const COL_DESCONTADO_VT  = 'numeric_mm0r6cn0';

const response = $input.first().json;
const items = response.data?.items_page_by_column_values?.items || [];

const dividas = [];
for (const item of items) {
  const cols = {};
  for (const c of item.column_values) cols[c.id] = c.text;
  const status = (cols[COL_STATUS] || '').toUpperCase().trim();
  if (status !== 'PENDENTE' && status !== 'PARCIAL') continue;

  dividas.push({
    itemId: String(item.id),
    status,
    dataInicio: cols[COL_DATA_INICIO] || null,
    dataFim: cols[COL_DATA_FIM] || null,
    descontoVR: parseFloat(cols[COL_DESCONTO_VR]) || 0,
    descontoVT: parseFloat(cols[COL_DESCONTO_VT]) || 0,
    residualVR: parseFloat(cols[COL_RESIDUAL_VR]) || 0,
    residualVT: parseFloat(cols[COL_RESIDUAL_VT]) || 0,
    descontadoVR: parseFloat(cols[COL_DESCONTADO_VR]) || 0,
    descontadoVT: parseFloat(cols[COL_DESCONTADO_VT]) || 0
  });
}

dividas.sort((a, b) => (a.dataInicio || '').localeCompare(b.dataInicio || ''));

return [{
  json: {
    ...dados,
    dividas,
    temDividas: dividas.length > 0
  }
}];

// ============================================================
// NÓ 10 — Aplicar dívidas FIFO ao benefício bruto
// ============================================================

const dados = $input.first().json;
const round = (n) => Math.round(n * 100) / 100;

let saldoVR = dados.valorBrutoVR;
let saldoVT = dados.valorBrutoVT;

const updates = [];
for (const d of dados.dividas) {
  let aplicadoVR = 0, aplicadoVT = 0;

  if (saldoVR > 0 && d.residualVR > 0) {
    aplicadoVR = Math.min(saldoVR, d.residualVR);
    saldoVR = round(saldoVR - aplicadoVR);
    d.residualVR = round(d.residualVR - aplicadoVR);
    d.descontadoVR = round(d.descontadoVR + aplicadoVR);
  }
  if (saldoVT > 0 && d.residualVT > 0) {
    aplicadoVT = Math.min(saldoVT, d.residualVT);
    saldoVT = round(saldoVT - aplicadoVT);
    d.residualVT = round(d.residualVT - aplicadoVT);
    d.descontadoVT = round(d.descontadoVT + aplicadoVT);
  }

  if (aplicadoVR > 0 || aplicadoVT > 0) {
    const novoStatus = (d.residualVR === 0 && d.residualVT === 0) ? 'FINALIZADO' : 'PARCIAL';
    updates.push({
      itemId: d.itemId,
      column_values_json: JSON.stringify({
        numeric_mm0rqy6z: String(d.descontadoVR),
        numeric_mm0r6cn0: String(d.descontadoVT),
        numeric_mm0r1691: String(d.residualVR),
        numeric_mm0rtwwg: String(d.residualVT),
        color_mm0r8mjr:   { label: novoStatus }
      }),
      novoStatus,
      aplicadoVR,
      aplicadoVT
    });
  }

  if (saldoVR === 0 && saldoVT === 0) break;
}

const valorLiquidoVR = round(saldoVR);
const valorLiquidoVT = round(saldoVT);

// Retorna 1 item por update — Split In Batches no node seguinte percorre.
// Se nenhum update: retorna 1 item vazio (com saldo) pra Code 7 funcionar.
if (updates.length === 0) {
  return [{
    json: {
      ...dados,
      valorLiquidoVR,
      valorLiquidoVT,
      updates: [],
      totalAplicadoVR: 0,
      totalAplicadoVT: 0
    }
  }];
}

return updates.map((u, idx) => ({
  json: {
    ...(idx === 0 ? dados : {}),
    ...u,
    valorLiquidoVR,
    valorLiquidoVT,
    totalAplicadoVR: round(dados.valorBrutoVR - valorLiquidoVR),
    totalAplicadoVT: round(dados.valorBrutoVT - valorLiquidoVT)
  }
}));

// ============================================================
// NÓ 12 — Consolidar valores finais (pós-Merge)
// ============================================================

let valorFinalVR, valorFinalVT, dados, caminhoDesconto;

try {
  const com = $('Code in JavaScript6').first().json;
  valorFinalVR = com.valorLiquidoVR;
  valorFinalVT = com.valorLiquidoVT;
  dados = com;
  caminhoDesconto = true;
} catch (e) {
  const sem = $('Code in JavaScript5').first().json;
  valorFinalVR = sem.valorBrutoVR;
  valorFinalVT = sem.valorBrutoVT;
  dados = sem;
  caminhoDesconto = false;
}

const valorFinalTotal = Math.round((valorFinalVR + valorFinalVT) * 100) / 100;

return [{
  json: {
    nomeEmpregado: dados.nomeEmpregado,
    chapaRM: dados.chapaRM,
    secaoRM: dados.secaoRM,
    descricaoSecaoRM: dados.descricaoSecaoRM,
    funcaoRM: dados.funcaoRM,
    dataAdmissaoRM: dados.dataAdmissaoRM,
    contrato: dados.contrato,
    funcao: dados.funcao,
    regraAplicada: dados.regraAplicada,
    optanteVT: dados.optanteVT,
    trabalhaSabado: dados.trabalhaSabado,
    interior: dados.interior,
    dataInicio: dados.dataInicio,
    dataFim: dados.dataFim,
    diasVR: dados.diasVR,
    diasVT: dados.diasVT,
    vrDia: dados.vrDia,
    vtDia: dados.vtDia,
    valorBrutoVR: dados.valorBrutoVR,
    valorBrutoVT: dados.valorBrutoVT,
    descontoAplicadoVR: caminhoDesconto ? (dados.totalAplicadoVR || 0) : 0,
    descontoAplicadoVT: caminhoDesconto ? (dados.totalAplicadoVT || 0) : 0,
    qtdDividasAplicadas: caminhoDesconto ? (dados.updates?.length || 0) : 0,
    valorFinalVR,
    valorFinalVT,
    valorFinalTotal,
    boardId: dados.boardId,
    itemId: dados.itemId
  }
}];

// ============================================================
// NÓ 17 — Calcular Separação Crédito vs Boleto
// ============================================================
// Lógica:
//   - 1 dia de VR + 1 dia de VT → crédito (EXISTING_BALANCE)
//   - Restante → boleto (PIX_CODE)
//   - Se valor final < 1 dia, tudo vai no crédito
//   - Valores em centavos para a API Caju
// ============================================================

// --- Referências aos nós ---
const consolidado = $('Code in JavaScript7').first().json; // Nó 12 - Consolidação
// ↑ AJUSTE O NOME conforme seu workflow

const employeeId = $input.first().json.items[0].employeeId;
const cpfCaju = $input.first().json.items[0].cpf;
const fullNameCaju = $input.first().json.items[0].fullName;

// Valores finais (já com desconto aplicado, se houve)
const valorFinalVR = consolidado.valorFinalVR;
const valorFinalVT = consolidado.valorFinalVT;
const vrDia = consolidado.vrDia;
const vtDia = consolidado.vtDia;

// --- Separação VR: crédito vs boleto ---
let creditoVR = 0;
let boletoVR = 0;

if (valorFinalVR > 0) {
  if (valorFinalVR <= vrDia) {
    // Valor final menor ou igual a 1 dia: tudo no crédito
    creditoVR = valorFinalVR;
  } else {
    // 1 dia no crédito, restante no boleto
    creditoVR = vrDia;
    boletoVR = Math.round((valorFinalVR - vrDia) * 100) / 100;
  }
}

// --- Separação VT: crédito vs boleto ---
let creditoVT = 0;
let boletoVT = 0;

if (valorFinalVT > 0) {
  if (valorFinalVT <= vtDia) {
    creditoVT = valorFinalVT;
  } else {
    creditoVT = vtDia;
    boletoVT = Math.round((valorFinalVT - vtDia) * 100) / 100;
  }
}

// --- Totais ---
const totalCredito = Math.round((creditoVR + creditoVT) * 100) / 100;
const totalBoleto = Math.round((boletoVR + boletoVT) * 100) / 100;
const temBoleto = totalBoleto > 0;

// --- Conversão para centavos (API Caju) ---
const creditoVR_centavos = Math.round(creditoVR * 100);
const creditoVT_centavos = Math.round(creditoVT * 100);
const boletoVR_centavos = Math.round(boletoVR * 100);
const boletoVT_centavos = Math.round(boletoVT * 100);
const totalCredito_centavos = Math.round(totalCredito * 100);
const totalBoleto_centavos = Math.round(totalBoleto * 100);

// --- Nome do pedido (máx 27 caracteres) ---
const hoje = new Date();
const dataFormatada = hoje.toLocaleDateString('pt-BR'); // DD/MM/YYYY
const nomeBase = `INT-${consolidado.nomeEmpregado}`;
const nomePedidoCredito = `${nomeBase}-${dataFormatada}`.substring(0, 27);
const nomePedidoBoleto = `${nomeBase}-B-${dataFormatada}`.substring(0, 27);

// --- Monta allowances do crédito ---
const allowancesCredito = [];
if (creditoVR_centavos > 0) {
  allowancesCredito.push({ category: 'FOOD_AID', amount: creditoVR_centavos });
}
if (creditoVT_centavos > 0) {
  allowancesCredito.push({ category: 'TRANSPORTATION', amount: creditoVT_centavos });
}

// --- Monta allowances do boleto ---
const allowancesBoleto = [];
if (boletoVR_centavos > 0) {
  allowancesBoleto.push({ category: 'FOOD_AID', amount: boletoVR_centavos });
}
if (boletoVT_centavos > 0) {
  allowancesBoleto.push({ category: 'TRANSPORTATION', amount: boletoVT_centavos });
}

return [{
  json: {
    // Dados do fluxo
    ...consolidado,

    // Dados Caju
    employeeId,
    cpfCaju,
    fullNameCaju,
    sponsorId: '5ff5cdc3-c55a-46b3-8a47-29479bf5ad35',

    // Valores separados (reais)
    creditoVR,
    creditoVT,
    totalCredito,
    boletoVR,
    boletoVT,
    totalBoleto,
    temBoleto,

    // Valores em centavos
    creditoVR_centavos,
    creditoVT_centavos,
    totalCredito_centavos,
    boletoVR_centavos,
    boletoVT_centavos,
    totalBoleto_centavos,

    // Payloads prontos para os HTTP Requests
    payloadCredito: {
      sponsorId: '5ff5cdc3-c55a-46b3-8a47-29479bf5ad35',
      name: nomePedidoCredito,
      allowances: [{
        employeeId,
        amounts: allowancesCredito
      }]
    },

    payloadBoleto: {
      sponsorId: '5ff5cdc3-c55a-46b3-8a47-29479bf5ad35',
      name: nomePedidoBoleto,
      allowances: [{
        employeeId,
        amounts: allowancesBoleto
      }]
    },

    // Payloads de confirmação
    payloadConfirmarCredito: {
      paymentStrategies: [{
        paymentType: 'EXISTING_BALANCE',
        amount: totalCredito_centavos
      }]
    },

    payloadConfirmarBoleto: {
      paymentStrategies: [{
        paymentType: 'PIX_CODE',
        amount: totalBoleto_centavos
      }]
    }
  }
}];

// ============================================================
// NÓ 23 — Montar XMLs SOAP para Histórico de Benefícios (RM Labore)
// ============================================================
// Entrada: dados consolidados do fluxo (Nó 17)
// Saída: até 4 soapBody prontos para HTTP Requests
// ============================================================
// Registros a criar:
//   1. Crédito VR → CODBENEFICIO=1, TPBEN=1 (mensal)
//   2. Crédito VT → CODBENEFICIO=2, TPBEN=1 (mensal)
//   3. Boleto VR  → CODBENEFICIO=1, TPBEN=0 (diário)  [se houver]
//   4. Boleto VT  → CODBENEFICIO=2, TPBEN=0 (diário)  [se houver]
// ============================================================

// AJUSTE o nome do nó conforme seu workflow
const dados = $('Code in JavaScript8').first().json; // Nó 17

const hoje = new Date();
const anoComp = hoje.getFullYear();
const mesComp = hoje.getMonth() + 1; // getMonth() é 0-indexed
const chapa = dados.chapaRM;
const nome = dados.nomeEmpregado;

// Função auxiliar para montar o SOAP envelope
function montarSoap(codBeneficio, vlrTotal, tpBen) {
  const xml = `<PRJ3230976>
              <ZMDHSTBENFUNC>
                <ID>-1</ID>
                <CODCOLIGADA>3</CODCOLIGADA>
                <ANOCOMP>${anoComp}</ANOCOMP>
                <MESCOMP>${mesComp}</MESCOMP>
                <ANOREF>${anoComp}</ANOREF>
                <MESREF>${mesComp}</MESREF>
                <CHAPA>${chapa}</CHAPA>
                <NOME>${nome}</NOME>
                <CODBENEFICIO>${codBeneficio}</CODBENEFICIO>
                <VLRTOTAL>${vlrTotal}</VLRTOTAL>
                <TPBEN>${tpBen}</TPBEN>
                <CATFUN>1</CATFUN>
              </ZMDHSTBENFUNC>
            </PRJ3230976>`;

  return `<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:tot="http://www.totvs.com/">
   <soapenv:Header/>
   <soapenv:Body>
      <tot:SaveRecord>
         <tot:DataServerName>RMSPRJ3230976Server</tot:DataServerName>
         <tot:XML><![CDATA[${xml}]]></tot:XML>
         <tot:Contexto>CODCOLIGADA=3; USUARIO=003080</tot:Contexto>
      </tot:SaveRecord>
   </soapenv:Body>
</soapenv:Envelope>`;
}

const registros = [];

// --- Crédito VR (sempre, se > 0) ---
if (dados.creditoVR > 0) {
  registros.push({
    tipo: 'CREDITO_VR',
    soapBody: montarSoap(1, dados.creditoVR, 1),
    valor: dados.creditoVR
  });
}

// --- Crédito VT (sempre, se > 0) ---
if (dados.creditoVT > 0) {
  registros.push({
    tipo: 'CREDITO_VT',
    soapBody: montarSoap(2, dados.creditoVT, 1),
    valor: dados.creditoVT
  });
}

// --- Boleto VR (só se houver) ---
if (dados.boletoVR > 0) {
  registros.push({
    tipo: 'BOLETO_VR',
    soapBody: montarSoap(1, dados.boletoVR, 0),
    valor: dados.boletoVR
  });
}

// --- Boleto VT (só se houver) ---
if (dados.boletoVT > 0) {
  registros.push({
    tipo: 'BOLETO_VT',
    soapBody: montarSoap(2, dados.boletoVT, 0),
    valor: dados.boletoVT
  });
}

// Retorna array de itens — cada um será processado pelo nó seguinte
return registros.map(r => ({ json: r }));
